#include <bits/stdc++.h>
using namespace std;
const int N=3e4+4;
int n,f[N],dist[N],siz[N];
int father(int x){
    if(f[x]!=x){
        int fa=f[x];
        f[x]=father(f[x]);
        dist[x]+=dist[fa];
    }
    return f[x];
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fx]=fy,dist[fx]=siz[fy],siz[fy]+=siz[fx];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=3e4;i++)
        f[i]=i,siz[i]=1;
    while(n--){
        char op;
        int x,y;
        cin>>op;
        if(op=='M'){
            scanf("%d%d",&y,&x);
            merge(x,y);
        }else{
            scanf("%d%d",&x,&y);
            int fx=father(x),fy=father(y);
            if(fx==fy)
                printf("%d\n",abs(dist[x]-dist[y])-1);
            else
                printf("-1\n");
        }
    }
    return 0;
}
